// Assuming bcrypt is used for password hashing and a secure token generation library is available

const bcrypt = require('bcrypt');
const crypto = require('crypto');
const express = require('express');
const cookieParser = require('cookie-parser');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(cookieParser());
app.use(express.json());

const users = {}; // Mock user database
const sessions = {}; // Mock session storage

const loginRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // Limit each IP to 5 login requests per windowMs
  message: "Too many login attempts, please try again later."
});

function generateToken() {
  return crypto.randomBytes(64).toString('hex');
}

app.post('/login', loginRateLimiter, async (req, res) => {
  const { username, password, rememberMe } = req.body;
  const user = users[username];

  if (!user) {
    return res.status(401).send('Invalid username or password');
  }

  const passwordMatch = await bcrypt.compare(password, user.passwordHash);
  if (!passwordMatch) {
    return res.status(401).send('Invalid username or password');
  }

  const sessionToken = generateToken();
  sessions[sessionToken] = { username, expires: Date.now() + (rememberMe ? 30 * 24 * 60 * 60 * 1000 : 24 * 60 * 60 * 1000) };

  res.cookie('session', sessionToken, { httpOnly: true, secure: true, maxAge: rememberMe ? 30 * 24 * 60 * 60 * 1000 : 24 * 60 * 60 * 1000 });
  res.send('Logged in successfully');
});

app.get('/auto-login', (req, res) => {
  const sessionToken = req.cookies.session;
  const session = sessions[sessionToken];

  if (!session || session.expires < Date.now()) {
    return res.status(401).send('Session expired or invalid');
  }

  res.send(`Welcome back, ${session.username}`);
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});